{
  "plan": [
    {
      "tool": "mongo.aggregate",
      "arguments": {
        "collection": "sam_licenses",
        "pipeline": [
          {
            "$match": {
              "publisher": "Adobe"
            }
          },
          {
            "$project": {
              "license_id": 1,
              "product": 1,
              "seat_count": 1,
              "term_end": 1,
              "status": 1,
              "contract_value_usd": 1,
              "assigned_team": 1
            }
          },
          {
            "$group": {
              "_id": "$product",
              "total_licensed_seats": {
                "$sum": "$seat_count"
              },
              "total_contract_value": {
                "$sum": "$contract_value_usd"
              },
              "license_count": {
                "$sum": 1
              },
              "active_licenses": {
                "$sum": {
                  "$cond": [
                    {
                      "$eq": [
                        "$status",
                        "active"
                      ]
                    },
                    1,
                    0
                  ]
                }
              }
            }
          }
        ]
      },
      "depends_on": []
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "sql": "SELECT cf.publisher, cf.product, cf.fiscal_quarter, SUM(cf.daily_active_seats) as total_seats_used, COUNT(DISTINCT cf.user_id) as monthly_active_users, COUNT(DISTINCT cf.product) as product_categories, SUM(cf.amount_usd) as total_spend FROM consumption_facts cf WHERE cf.publisher = 'Adobe' AND cf.fiscal_quarter = 4 AND cf.event_date >= '2023-10-01' AND cf.event_date <= '2023-12-31' GROUP BY cf.publisher, cf.product, cf.fiscal_quarter ORDER BY cf.product"
      },
      "depends_on": []
    },
    {
      "tool": "mongo.update",
      "arguments": {
        "collection": "sam_reconciliation",
        "filter": {
          "publisher": "Adobe",
          "quarter": "Q4"
        },
        "update": {
          "$set": {
            "publisher": "Adobe",
            "quarter": "Q4",
            "license_inventory": "$1.results",
            "q4_usage": "$2.results",
            "reconciliation_timestamp": {
              "$literal": "$$NOW"
            },
            "variance_analysis": {
              "$literal": "pending_calculation"
            },
            "posture_status": {
              "$literal": "pending_assessment"
            }
          }
        },
        "upsert": true
      },
      "depends_on": [
        1,
        2
      ]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "adobe_license_reconciliation_initiated",
        "resource_type": "sam_licenses",
        "resource_id": "Adobe_Q4_2023
